import{_ as t,o as s,c as e,a2 as n}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"个人工具与知识库","description":"","frontmatter":{},"headers":[],"relativePath":"projects/knowledge-tools/index.md","filePath":"projects/knowledge-tools/index.md"}'),i={name:"projects/knowledge-tools/index.md"};function l(o,a,d,p,r,h){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="个人工具与知识库" tabindex="-1">个人工具与知识库 <a class="header-anchor" href="#个人工具与知识库" aria-label="Permalink to &quot;个人工具与知识库&quot;">​</a></h1><blockquote><p>这一组项目属于我的长期能力建设系统。它们展示的是我如何把学习资料、知识笔记、考试题库、个人研究和公开内容整理成 <span class="text-highlight">可结构化、可复用、可发布、可持续迭代</span> 的个人工具体系。</p></blockquote><div class="project-snapshot"><div><strong>2 个项目</strong><span>证券考试辅助工具、FlowMindLab / Obsidian 个人知识库</span></div><div><strong>学习数据化</strong><span>题库、讲义、错题、章节、考点和练习进度</span></div><div><strong>知识资产化</strong><span>Obsidian、Quartz、MOC、双链和主题地图</span></div><div><strong>AI 协作</strong><span>用 AI 辅助整理资料、生成工具、搭建系统和复盘过程</span></div></div><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>公司项目证明的是我在真实业务中的产品落地、数据治理和跨团队协作能力。个人工具与知识库项目证明的是另一种能力：我会主动把自己的学习、考试、知识管理和长期研究做成系统。</p><p>这类项目的价值不在于“规模大”，而在于它们体现了稳定的方法：</p><ul><li>面对混乱资料，先建立结构。</li><li>面对重复劳动，优先工具化。</li><li>面对学习过程，尽量数据化。</li><li>面对长期知识，建立可导航的知识地图。</li><li>面对 AI，关注它如何嵌入真实流程，避免只停留在对话。</li></ul><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>类型</th><th>展示能力</th></tr></thead><tbody><tr><td><a href="/projects/knowledge-tools/securities-exam-tool.html">证券考试辅助项目</a></td><td>个人学习工具 / AI 辅助备考系统</td><td>内容结构化、题库整理、讲义溯源、本地练习页、学习数据复盘</td></tr><tr><td><a href="/projects/knowledge-tools/flowmindlab-quartz.html">FlowMindLab / Obsidian 个人知识库</a></td><td>个人知识系统 / Quartz 公开站</td><td>Obsidian 仓库、Markdown、MOC、主题地图、知识库发布和长期内容管理</td></tr></tbody></table><h2 id="共同方法" tabindex="-1">共同方法 <a class="header-anchor" href="#共同方法" aria-label="Permalink to &quot;共同方法&quot;">​</a></h2><p>这两个项目背后的方法是一致的：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始资料</span></span>
<span class="line"><span>  -&gt; 结构化整理</span></span>
<span class="line"><span>  -&gt; 标签 / 目录 / 字段</span></span>
<span class="line"><span>  -&gt; 工具或知识站</span></span>
<span class="line"><span>  -&gt; 使用反馈</span></span>
<span class="line"><span>  -&gt; 持续迭代</span></span></code></pre></div><p>证券考试项目偏“学习数据产品”：把题目、讲义、章节、考点和做题行为整理成可决策的复习系统。FlowMindLab 偏“长期知识资产”：把个人学习和项目经验整理成可导航、可发布、可复用的知识地图。</p><h2 id="展示价值" tabindex="-1">展示价值 <a class="header-anchor" href="#展示价值" aria-label="Permalink to &quot;展示价值&quot;">​</a></h2><p>个人项目往往更能看出一个人的主动性。它们说明我不只在工作中做数据产品，也会把同样的方法用在自己的学习和知识管理上。</p><p>对 HR 和面试官来说，这组项目可以补充证明：</p><ul><li>我具备把非结构化资料转成结构化系统的能力。</li><li>我能用 AI 和自动化工具解决真实问题。</li><li>我重视过程沉淀，也重视最终结果。</li><li>我有持续学习、持续整理和长期维护系统的习惯。</li></ul>`,17)])])}const u=t(i,[["render",l]]);export{b as __pageData,u as default};
